/* ═══════════════════════════════════════════════════════════════
   Compute summary counts
   ═══════════════════════════════════════════════════════════════ */
(function() {
    var cfg = window.CHECKLIST_CONFIG;
    var summary = { pass: 0, fail: 0, warn: 0, pending: 0 };
    cfg.cards.forEach(function(card) {
        card.checks.forEach(function(check) {
            if (summary[check.status] !== undefined) {
                summary[check.status]++;
            }
        });
    });
    cfg.constants.summary = summary;
})();
